BEGIN;
DO $$
DECLARE
  subject_id UUID;
  topic_id UUID;
  test_id BIGINT;
BEGIN
  SELECT id INTO subject_id FROM test_subjects WHERE name ILIKE '%cardio%' LIMIT 1;
  SELECT test_id INTO test_id FROM test_configs WHERE subject_id = subject_id LIMIT 1;
  SELECT id INTO topic_id FROM test_topics WHERE name ILIKE '%ekg%' LIMIT 1;
  IF topic_id IS NULL THEN
    IF subject_id IS NULL THEN
      INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular', 'Cardio notes') RETURNING id INTO subject_id;
    END IF;
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (subject_id, 'EKG', 'Electrocardiogram analysis', 'published') RETURNING id INTO topic_id;
  END IF;

  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When analyzing the cardiac conduction system, which component accurately reflects SA Node?', 'When analyzing the cardiac conduction system, which component accurately reflects SA Node?', '[{"id": "a", "text": "An irregular rate without pacemaker of the heart"}, {"id": "b", "text": "fires at 60-100 bpm only"}, {"id": "c", "text": "sends wave through atria alone without pacemaker of the heart"}, {"id": "d", "text": "pacemaker of the heart, which fires at 60-100 bpm, and sends wave through atria"}]'::jsonb, '["d"]', 'SA Node is associated with pacemaker of the heart. It fires at 60-100 bpm, and sends wave through atria.', 'EKG', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is evaluating an ECG strip and identifies characteristics of AV Node. Which finding confirms this?', 'The nurse is evaluating an ECG strip and identifies characteristics of AV Node. Which finding confirms this?', '[{"id": "a", "text": "Complete absence of P waves"}, {"id": "b", "text": "Pauses the signal to let the atria empty before the ventricles contract"}, {"id": "c", "text": "gatekeeper"}, {"id": "d", "text": "An inverted T wave with shortened PR"}]'::jsonb, '["c"]', 'The key characteristic of the AV node is its gatekeeper role; it pauses the signal to let the atria empty before the ventricles contract.', 'EKG', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client''s rhythm strip demonstrates features of Bundle of His. What is the priority nursing intervention or key finding?', 'A client''s rhythm strip demonstrates features of Bundle of His. What is the priority nursing intervention or key finding?', '[{"id": "a", "text": "Administer epinephrine immediately"}, {"id": "b", "text": "Ignore the rhythm as it is an artifact"}, {"id": "c", "text": "Perform unsynchronized defibrillation"}, {"id": "d", "text": "ventricles contract"}]'::jsonb, '["d"]', 'For the Bundle of His, a key finding is ventricular contraction. It is the pathway to the left and right bundle branches and leads to Purkinje fibers.', 'EKG', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'Which statement regarding Depolarization is correct based on standard ECG analysis?', 'Which statement regarding Depolarization is correct based on standard ECG analysis?', '[{"id": "a", "text": "It requires immediate defibrillation regardless of pulse"}, {"id": "b", "text": "It is represented by Na+ entering the cell"}, {"id": "c", "text": "It is defined by the charge going from negative to positive"}, {"id": "d", "text": "It indicates normal ventricular repolarization"}]'::jsonb, '["c"]', 'Characteristics of depolarization include Na+ entering the cell and the charge changing from negative to positive.', 'EKG', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A novice nurse is asking about Repolarization. The preceptor provides correct teaching by stating:', 'A novice nurse is asking about Repolarization. The preceptor provides correct teaching by stating:', '[{"id": "a", "text": "It is characterized strictly by an absent QRS."}, {"id": "b", "text": "It always requires synchronized cardioversion."}, {"id": "c", "text": "It represents normal atrial repolarization."}, {"id": "d", "text": "It involves cell resets and positive to negative."}]'::jsonb, '["d"]', 'Repolarization involves cell resets and positive to negative. Toward lead = dip DOWN; Away = bump UP.', 'EKG', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When analyzing the cardiac conduction system, which component accurately reflects P Wave?', 'When analyzing the cardiac conduction system, which component accurately reflects P Wave?', '[{"id": "a", "text": "0.08\u20130.10 sec only"}, {"id": "b", "text": "2\u20132.5 small boxes alone without Atrial depolarization"}, {"id": "c", "text": "An irregular rate without Atrial depolarization"}, {"id": "d", "text": "Atrial depolarization, which 0.08\u20130.10 sec, and 2\u20132.5 small boxes"}]'::jsonb, '["d"]', 'P Wave is associated with Atrial depolarization. It 0.08–0.10 sec, and 2–2.5 small boxes.', 'EKG', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is evaluating an ECG strip and identifies characteristics of PR Interval. Which finding confirms this?', 'The nurse is evaluating an ECG strip and identifies characteristics of PR Interval. Which finding confirms this?', '[{"id": "a", "text": "0.12\u20130.20 sec but with opposing 3\u20135 small boxes"}, {"id": "b", "text": "An inverted T wave with shortened PR"}, {"id": "c", "text": "SA to AV node conduction time"}, {"id": "d", "text": "Complete absence of P waves"}]'::jsonb, '["c"]', 'The key characteristic of PR Interval is SA to AV node conduction time. 0.12–0.20 sec may also be seen.', 'EKG', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client''s rhythm strip demonstrates features of PR Segment. What is the priority nursing intervention or key finding?', 'A client''s rhythm strip demonstrates features of PR Segment. What is the priority nursing intervention or key finding?', '[{"id": "a", "text": "Administer epinephrine immediately"}, {"id": "b", "text": "Ignore the rhythm as it is an artifact"}, {"id": "c", "text": "1\u20133 small boxes"}, {"id": "d", "text": "Perform unsynchronized defibrillation"}]'::jsonb, '["c"]', 'For the PR segment, a key finding is 1–3 small boxes. It reflects AV node delay and typically lasts 0.04–0.12 sec.', 'EKG', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'Which statement regarding QRS Complex is correct based on standard ECG analysis?', 'Which statement regarding QRS Complex is correct based on standard ECG analysis?', '[{"id": "a", "text": "It is defined by <0.12 sec (narrow)"}, {"id": "b", "text": "It is represented by Ventricular depolarization but only when >150 bpm"}, {"id": "c", "text": "It requires immediate defibrillation regardless of pulse"}, {"id": "d", "text": "It indicates normal ventricular repolarization"}]'::jsonb, '["a"]', 'Characteristics of the QRS complex include ventricular depolarization and a normal width of <0.12 sec (narrow).', 'EKG', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A novice nurse is asking about T Wave. The preceptor provides correct teaching by stating:', 'A novice nurse is asking about T Wave. The preceptor provides correct teaching by stating:', '[{"id": "a", "text": "It always requires synchronized cardioversion."}, {"id": "b", "text": "It represents normal atrial repolarization."}, {"id": "c", "text": "It involves ventricular repolarization and has a variable duration of 0.10\u20130.25 sec."}, {"id": "d", "text": "It is characterized strictly by an absent QRS."}]'::jsonb, '["c"]', 'The T wave reflects ventricular repolarization and has a variable duration of approximately 0.10–0.25 sec.', 'EKG', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When analyzing the cardiac conduction system, which component accurately reflects U Wave?', 'When analyzing the cardiac conduction system, which component accurately reflects U Wave?', '[{"id": "a", "text": "It is always present in all normal ECGs"}, {"id": "b", "text": "It may indicate hypokalemia"}, {"id": "c", "text": "It is a marker of acute STEMI"}, {"id": "d", "text": "It is not always present and may indicate hypokalemia when prominent"}]'::jsonb, '["d"]', 'The U wave is not always present; when prominent, it may indicate hypokalemia.', 'EKG', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is evaluating an ECG strip and identifies characteristics of Cardioversion. Which finding confirms this?', 'The nurse is evaluating an ECG strip and identifies characteristics of Cardioversion. Which finding confirms this?', '[{"id": "a", "text": "Complete absence of P waves"}, {"id": "b", "text": "LOW energy, SYNC ON (R wave) but with opposing SVT, A-Fib, A-Flutter, V-Tach with pulse"}, {"id": "c", "text": "An inverted T wave with shortened PR"}, {"id": "d", "text": "Patient HAS a pulse"}]'::jsonb, '["d"]', 'The key characteristic of Cardioversion is Patient HAS a pulse. LOW energy, SYNC ON (R wave) may also be seen.', 'EKG', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client''s rhythm strip demonstrates features of Defibrillation. What is the priority nursing intervention or key finding?', 'A client''s rhythm strip demonstrates features of Defibrillation. What is the priority nursing intervention or key finding?', '[{"id": "a", "text": "Ignore the rhythm as it is an artifact"}, {"id": "b", "text": "Administer epinephrine immediately"}, {"id": "c", "text": "V-Fib, pulseless V-Tach. Needs CPR"}, {"id": "d", "text": "Perform unsynchronized defibrillation"}]'::jsonb, '["c"]', 'For defibrillation, a key indication is V-Fib or pulseless V-Tach requiring CPR. The patient has no pulse, and high energy is delivered with SYNC OFF (immediate).', 'EKG', false, 13, 1, true);
