  VALUES (test_id, topic_id, 'Which statement regarding Grid Paper Speed is correct based on standard ECG analysis?', 'Which statement regarding Grid Paper Speed is correct based on standard ECG analysis?', '[{"id": "a", "text": "It is represented by 25 mm/sec but only when >150 bpm"}, {"id": "b", "text": "It indicates normal ventricular repolarization"}, {"id": "c", "text": "It requires immediate defibrillation regardless of pulse"}, {"id": "d", "text": "It is defined by standard speed"}]'::jsonb, '["d"]', 'Characteristics of ECG grid paper speed include 25 mm/sec, which is the standard recording speed.', 'EKG', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A novice nurse is asking about Small Box. The preceptor provides correct teaching by stating:', 'A novice nurse is asking about Small Box. The preceptor provides correct teaching by stating:', '[{"id": "a", "text": "It involves 0.04 s and 1 mm width."}, {"id": "b", "text": "It is characterized strictly by an absent QRS."}, {"id": "c", "text": "It represents normal atrial repolarization."}, {"id": "d", "text": "It always requires synchronized cardioversion."}]'::jsonb, '["a"]', 'Small Box involves 0.04 s and 1 mm width. QRS width, P-wave duration.', 'EKG', false, 15, 1, true);
