  VALUES (test_id, topic_id, 'When analyzing the cardiac conduction system, which component accurately reflects Large Box?', 'When analyzing the cardiac conduction system, which component accurately reflects Large Box?', '[{"id": "a", "text": "PR interval, QRS duration alone without 0.20 s"}, {"id": "b", "text": "0.20 s, which 5 small boxes, and PR interval, QRS duration"}, {"id": "c", "text": "An irregular rate without 0.20 s"}, {"id": "d", "text": "5 small boxes only"}]'::jsonb, '["b"]', 'Large Box is associated with 0.20 s. It 5 small boxes, and PR interval, QRS duration.', 'EKG', false, 16, 1, true);
