  VALUES (test_id, topic_id, 'The nurse is evaluating an ECG strip and identifies characteristics of One Second. Which finding confirms this?', 'The nurse is evaluating an ECG strip and identifies characteristics of One Second. Which finding confirms this?', '[{"id": "a", "text": "An inverted T wave with shortened PR"}, {"id": "b", "text": "Complete absence of P waves"}, {"id": "c", "text": "5 large boxes but with opposing HR Calculation"}, {"id": "d", "text": "1.00 s"}]'::jsonb, '["d"]', 'The key characteristic of One Second is 1.00 s. 5 large boxes may also be seen.', 'EKG', false, 17, 1, true);
