  VALUES (test_id, topic_id, 'A client''s rhythm strip demonstrates features of Heart Rate: Regular. What is the priority nursing intervention or key finding?', 'A client''s rhythm strip demonstrates features of Heart Rate: Regular. What is the priority nursing intervention or key finding?', '[{"id": "a", "text": "Administer epinephrine immediately"}, {"id": "b", "text": "Ignore the rhythm as it is an artifact"}, {"id": "c", "text": "None of the above"}, {"id": "d", "text": "Perform unsynchronized defibrillation"}]'::jsonb, '["c"]', 'For Heart Rate: Regular, the key finding/intervention is . It 300 ÷ Large Boxes and between two R-wave peaks.', 'EKG', false, 18, 1, true);
