  VALUES (test_id, topic_id, 'Which statement regarding Heart Rate: Irregular is correct based on standard ECG analysis?', 'Which statement regarding Heart Rate: Irregular is correct based on standard ECG analysis?', '[{"id": "a", "text": "It indicates normal ventricular repolarization"}, {"id": "b", "text": "It is represented by QRS Count \u00d7 10 but only when >150 bpm"}, {"id": "c", "text": "It requires immediate defibrillation regardless of pulse"}, {"id": "d", "text": "It is defined by in a 6-second strip (30 large boxes)"}]'::jsonb, '["d"]', 'Characteristics of Heart Rate: Irregular include: QRS Count × 10. It in a 6-second strip (30 large boxes).', 'EKG', false, 19, 1, true);
