  VALUES (test_id, topic_id, 'When analyzing the cardiac conduction system, which component accurately reflects Normal Sinus Rhythm?', 'When analyzing the cardiac conduction system, which component accurately reflects Normal Sinus Rhythm?', '[{"id": "a", "text": "60-100 bpm, which Regular rhythm, consistent P waves, PR 0.12-0.20, and No treatment needed"}, {"id": "b", "text": "An irregular rate without 60-100 bpm"}, {"id": "c", "text": "No treatment needed alone without 60-100 bpm"}, {"id": "d", "text": "Regular rhythm, consistent P waves, PR 0.12-0.20 only"}]'::jsonb, '["a"]', 'Normal Sinus Rhythm is associated with 60-100 bpm. It Regular rhythm, consistent P waves, PR 0.12-0.20, and No treatment needed.', 'EKG', false, 21, 1, true);
