  VALUES (test_id, topic_id, 'The nurse is evaluating an ECG strip and identifies characteristics of Sinus Bradycardia. Which finding confirms this?', 'The nurse is evaluating an ECG strip and identifies characteristics of Sinus Bradycardia. Which finding confirms this?', '[{"id": "a", "text": "<60 bpm"}, {"id": "b", "text": "Complete absence of P waves"}, {"id": "c", "text": "Regular, normal P waves but with opposing Symptomatic: Atropine. Asymptomatic: Monitor"}, {"id": "d", "text": "An inverted T wave with shortened PR"}]'::jsonb, '["a"]', 'The key characteristic of Sinus Bradycardia is <60 bpm. Regular, normal P waves may also be seen.', 'EKG', false, 22, 1, true);
