  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A novice nurse is asking about Atrial Flutter. The preceptor provides correct teaching by stating:', 'A novice nurse is asking about Atrial Flutter. The preceptor provides correct teaching by stating:', '[{"id": "a", "text": "It always requires synchronized cardioversion."}, {"id": "b", "text": "It involves 250-350 bpm (atria) and Sawtooth F waves."}, {"id": "c", "text": "It is characterized strictly by an absent QRS."}, {"id": "d", "text": "It represents normal atrial repolarization."}]'::jsonb, '["b"]', 'Atrial Flutter involves 250-350 bpm (atria) and Sawtooth F waves. Anticoagulants, Beta-Blockers, Cardioversion.', 'EKG', false, 25, 1, true);
