  VALUES (test_id, topic_id, 'A client is at risk for complications related to Grid Paper Speed. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to Grid Paper Speed. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "It is 25 mm/sec"}, {"id": "b", "text": "It requires immediate chest compressions"}, {"id": "c", "text": "It involves standard ECG paper speed"}, {"id": "d", "text": "The key indicator is 25 mm/sec"}, {"id": "e", "text": "It strictly indicates a first-degree block"}]'::jsonb, '["a", "c", "d"]', 'For grid paper speed, key points are that standard ECG speed is 25 mm/sec and this setting is used for routine interpretation.', 'EKG', true, 64, 1, true);
