  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with One Second. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with One Second. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "HR Calculation"}, {"id": "b", "text": "It is treated with high-dose atropine"}, {"id": "c", "text": "1.00 s"}, {"id": "d", "text": "It always presents as wide QRS"}, {"id": "e", "text": "5 large boxes"}]'::jsonb, '["a", "c", "e"]', 'One Second features include 1.00 s, 5 large boxes, and HR Calculation.', 'EKG', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client is at risk for complications related to Heart Rate: Regular. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to Heart Rate: Regular. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "The key indicator is the number of large boxes between two R-wave peaks"}, {"id": "b", "text": "It uses the 300 \u00f7 large boxes method"}, {"id": "c", "text": "It requires immediate chest compressions"}, {"id": "d", "text": "It strictly indicates a first-degree block"}, {"id": "e", "text": "It involves counting between two R-wave peaks"}]'::jsonb, '["a", "b", "e"]', 'For a regular heart rate, use the 300 ÷ large boxes method by counting the large boxes between two R-wave peaks.', 'EKG', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When educating a client about Heart Rate: Irregular, the nurse should include which points? (Select all that apply)', 'When educating a client about Heart Rate: Irregular, the nurse should include which points? (Select all that apply)', '[{"id": "a", "text": "It is generally assessed in a 6-second strip (30 large boxes)."}, {"id": "b", "text": "It indicates normal repolarization."}, {"id": "c", "text": "It is often estimated using the QRS count × 10 method."}, {"id": "d", "text": "It demonstrates a flatline."}, {"id": "e", "text": "The condition involves QRS count × 10."}]'::jsonb, '["a", "c", "e"]', 'Teaching for irregular heart rate should include using a 6-second strip (30 large boxes) and estimating rate by QRS count × 10.', 'EKG', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'An assessment of Heart Rate: Quick on the ECG grid reveals which associated findings? (Select all that apply)', 'An assessment of Heart Rate: Quick on the ECG grid reveals which associated findings? (Select all that apply)', '[{"id": "a", "text": "Memorization rule"}, {"id": "b", "text": "Related factor: countdown sequence from 300"}, {"id": "c", "text": "Pacing spikes follow the T wave"}, {"id": "d", "text": "Usually benign with no intervention"}, {"id": "e", "text": "300, 150, 100, 75, 60, 50"}]'::jsonb, '["a", "b", "e"]', 'The quick heart-rate method uses the memorized sequence 300, 150, 100, 75, 60, 50 counted from the R-wave alignment.', 'EKG', true, 70, 1, true);
