  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with Normal Sinus Rhythm. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with Normal Sinus Rhythm. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "60-100 bpm"}, {"id": "b", "text": "No treatment needed"}, {"id": "c", "text": "It is treated with high-dose atropine"}, {"id": "d", "text": "It always presents as wide QRS"}, {"id": "e", "text": "Regular rhythm, consistent P waves, PR 0.12-0.20"}]'::jsonb, '["a", "b", "e"]', 'Normal Sinus Rhythm features include 60-100 bpm, Regular rhythm, consistent P waves, PR 0.12-0.20, and No treatment needed.', 'EKG', true, 71, 1, true);
