  VALUES (test_id, topic_id, 'A client is at risk for complications related to Sinus Bradycardia. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to Sinus Bradycardia. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "It requires immediate chest compressions"}, {"id": "b", "text": "It strictly indicates a first-degree block"}, {"id": "c", "text": "It <60 bpm"}, {"id": "d", "text": "The key indicator is Symptomatic: Atropine. Asymptomatic: Monitor"}, {"id": "e", "text": "It involves Regular, normal P waves"}]'::jsonb, '["c", "d", "e"]', 'For Sinus Bradycardia, it <60 bpm and involves Regular, normal P waves. Additionally, Symptomatic: Atropine. Asymptomatic: Monitor.', 'EKG', true, 72, 1, true);
