  VALUES (test_id, topic_id, 'When educating a client about Sinus Tachycardia, the nurse should include which points? (Select all that apply)', 'When educating a client about Sinus Tachycardia, the nurse should include which points? (Select all that apply)', '[{"id": "a", "text": "It indicates normal repolarization."}, {"id": "b", "text": "It Calcium Channel Blockers, Beta-Blockers, Digoxin."}, {"id": "c", "text": "It is generally defined by Regular, normal P."}, {"id": "d", "text": "The condition involves 100-150 bpm."}, {"id": "e", "text": "It demonstrates a flatline."}]'::jsonb, '["b", "c", "d"]', 'Teaching for Sinus Tachycardia should include: 100-150 bpm, Regular, normal P, and Calcium Channel Blockers, Beta-Blockers, Digoxin.', 'EKG', true, 73, 1, true);
