  VALUES (test_id, topic_id, 'When educating a client about V-Tach, the nurse should include which points? (Select all that apply)', 'When educating a client about V-Tach, the nurse should include which points? (Select all that apply)', '[{"id": "a", "text": "It demonstrates a flatline."}, {"id": "b", "text": "It is generally defined by Wide, bizarre QRS, no P."}, {"id": "c", "text": "It Pulse: Cardiovert. No Pulse: Defib + CPR."}, {"id": "d", "text": "It indicates normal repolarization."}, {"id": "e", "text": "The condition involves 100-250 bpm."}]'::jsonb, '["b", "c", "e"]', 'Teaching for V-Tach should include: 100-250 bpm, Wide, bizarre QRS, no P, and Pulse: Cardiovert. No Pulse: Defib + CPR.', 'EKG', true, 77, 1, true);
