  VALUES (test_id, topic_id, 'An assessment of V-Fib on the ECG grid reveals which associated findings? (Select all that apply)', 'An assessment of V-Fib on the ECG grid reveals which associated findings? (Select all that apply)', '[{"id": "a", "text": "Pacing spikes follow the T wave"}, {"id": "b", "text": "Related factor: Defibrillation (unsync), CPR, Epi, Amiodarone"}, {"id": "c", "text": "No effective pulse"}, {"id": "d", "text": "Chaotic, no QRS/P"}, {"id": "e", "text": "Usually benign with no intervention"}]'::jsonb, '["b", "c", "d"]', 'V-Fib is associated with No effective pulse and Chaotic, no QRS/P. Furthermore, Defibrillation (unsync), CPR, Epi, Amiodarone.', 'EKG', true, 78, 1, true);
