  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with PVCs. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with PVCs. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "It is treated with high-dose atropine"}, {"id": "b", "text": "It always presents as wide QRS"}, {"id": "c", "text": "3+ in row = V-Tach. Check electrolytes"}, {"id": "d", "text": "Occasional irregular beat"}, {"id": "e", "text": "Wide bizarre QRS, no preceding P"}]'::jsonb, '["c", "d", "e"]', 'PVCs features include Occasional irregular beat, Wide bizarre QRS, no preceding P, and 3+ in row = V-Tach. Check electrolytes.', 'EKG', true, 79, 1, true);
