  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with Depolarization. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with Depolarization. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "It is treated with high-dose atropine"}, {"id": "b", "text": "It always presents as wide QRS"}, {"id": "c", "text": "Na+ enters cell"}, {"id": "d", "text": "Toward a lead = bump UP; Away = dip DOWN"}, {"id": "e", "text": "charge goes negative to positive"}]'::jsonb, '["c", "d", "e"]', 'Depolarization features include Na+ enters cell, charge goes negative to positive, and Toward a lead = bump UP; Away = dip DOWN.', 'EKG', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client is at risk for complications related to Repolarization. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to Repolarization. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "It cell resets"}, {"id": "b", "text": "It strictly indicates a first-degree block"}, {"id": "c", "text": "The key indicator is Toward lead = dip DOWN; Away = bump UP"}, {"id": "d", "text": "It involves positive to negative"}, {"id": "e", "text": "It requires immediate chest compressions"}]'::jsonb, '["a", "c", "d"]', 'For Repolarization, it cell resets and involves positive to negative. Additionally, Toward lead = dip DOWN; Away = bump UP.', 'EKG', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When educating a client about P Wave, the nurse should include which points? (Select all that apply)', 'When educating a client about P Wave, the nurse should include which points? (Select all that apply)', '[{"id": "a", "text": "The condition involves Atrial depolarization."}, {"id": "b", "text": "It demonstrates a flatline."}, {"id": "c", "text": "It 2\u20132.5 small boxes."}, {"id": "d", "text": "It is generally defined by 0.08\u20130.10 sec."}, {"id": "e", "text": "It indicates normal repolarization."}]'::jsonb, '["a", "c", "d"]', 'Teaching for P Wave should include: Atrial depolarization, 0.08–0.10 sec, and 2–2.5 small boxes.', 'EKG', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'An assessment of PR Interval on the ECG grid reveals which associated findings? (Select all that apply)', 'An assessment of PR Interval on the ECG grid reveals which associated findings? (Select all that apply)', '[{"id": "a", "text": "SA to AV node conduction time"}, {"id": "b", "text": "Usually benign with no intervention"}, {"id": "c", "text": "Pacing spikes follow the T wave"}, {"id": "d", "text": "Related factor: 3\u20135 small boxes"}, {"id": "e", "text": "0.12\u20130.20 sec"}]'::jsonb, '["a", "d", "e"]', 'PR Interval is associated with SA to AV node conduction time and 0.12–0.20 sec. Furthermore, 3–5 small boxes.', 'EKG', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with PR Segment. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with PR Segment. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "It is treated with high-dose atropine"}, {"id": "b", "text": "0.04\u20130.12 sec"}, {"id": "c", "text": "It always presents as wide QRS"}, {"id": "d", "text": "AV node delay"}, {"id": "e", "text": "1\u20133 small boxes"}]'::jsonb, '["b", "d", "e"]', 'PR Segment features include AV node delay, 0.04–0.12 sec, and 1–3 small boxes.', 'EKG', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client is at risk for complications related to QRS Complex. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to QRS Complex. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "It requires immediate chest compressions"}, {"id": "b", "text": "It involves <0.12 sec (narrow)"}, {"id": "c", "text": "The key indicator is >0.12 sec is wide/abnormal"}, {"id": "d", "text": "It Ventricular depolarization"}, {"id": "e", "text": "It strictly indicates a first-degree block"}]'::jsonb, '["b", "c", "d"]', 'For QRS Complex, it Ventricular depolarization and involves <0.12 sec (narrow). Additionally, >0.12 sec is wide/abnormal.', 'EKG', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'When educating a client about T Wave, the nurse should include which points? (Select all that apply)', 'When educating a client about T Wave, the nurse should include which points? (Select all that apply)', '[{"id": "a", "text": "It demonstrates a flatline."}, {"id": "b", "text": "It indicates normal repolarization."}, {"id": "c", "text": "The condition involves ventricular repolarization."}, {"id": "d", "text": "It typically follows the QRS complex."}, {"id": "e", "text": "It is generally defined by a variable duration of 0.10\u20130.25 sec."}]'::jsonb, '["c", "d", "e"]', 'Teaching for the T wave should include that it reflects ventricular repolarization and has a variable duration of approximately 0.10–0.25 sec.', 'EKG', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'An assessment of U Wave on the ECG grid reveals which associated findings? (Select all that apply)', 'An assessment of U Wave on the ECG grid reveals which associated findings? (Select all that apply)', '[{"id": "a", "text": "May indicate hypokalemia"}, {"id": "b", "text": "Not always present"}, {"id": "c", "text": "Related factor: can become prominent with electrolyte imbalance"}, {"id": "d", "text": "Pacing spikes follow the T wave"}, {"id": "e", "text": "Usually benign with no intervention"}]'::jsonb, '["a", "b", "c"]', 'U waves are not always present and may indicate hypokalemia, especially when they become prominent with electrolyte imbalance.', 'EKG', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'The nurse is analyzing an ECG strip and notes criteria consistent with Cardioversion. Which of the following statements apply? (Select all that apply)', 'The nurse is analyzing an ECG strip and notes criteria consistent with Cardioversion. Which of the following statements apply? (Select all that apply)', '[{"id": "a", "text": "LOW energy, SYNC ON (R wave)"}, {"id": "b", "text": "It always presents as wide QRS"}, {"id": "c", "text": "SVT, A-Fib, A-Flutter, V-Tach with pulse"}, {"id": "d", "text": "It is treated with high-dose atropine"}, {"id": "e", "text": "Patient HAS a pulse"}]'::jsonb, '["a", "c", "e"]', 'Cardioversion features include Patient HAS a pulse, LOW energy, SYNC ON (R wave), and SVT, A-Fib, A-Flutter, V-Tach with pulse.', 'EKG', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (test_id, topic_id, 'A client is at risk for complications related to Defibrillation. Which of the following are clinical facts the nurse should remember? (Select all that apply)', 'A client is at risk for complications related to Defibrillation. Which of the following are clinical facts the nurse should remember? (Select all that apply)', '[{"id": "a", "text": "It strictly indicates a first-degree block"}, {"id": "b", "text": "The key indicator is V-Fib, pulseless V-Tach. Needs CPR"}, {"id": "c", "text": "It involves HIGH energy, SYNC OFF (immediate)"}, {"id": "d", "text": "It Patient has NO pulse"}, {"id": "e", "text": "It requires immediate chest compressions"}]'::jsonb, '["b", "c", "d"]', 'For Defibrillation, it Patient has NO pulse and involves HIGH energy, SYNC OFF (immediate). Additionally, V-Fib, pulseless V-Tach. Needs CPR.', 'EKG', true, 100, 1, true);

